        HttpUrl parsedUrl = HttpUrl.parse(url);
        if (parsedUrl == null) {
            throw new IllegalArgumentException("Invalid URL format");
        }

        // 2. Restrict to safe protocols (HTTP and HTTPS)
        String scheme = parsedUrl.scheme();
        if (!"http".equals(scheme) && !"https".equals(scheme)) {
            throw new IllegalArgumentException("Only HTTP and HTTPS protocols are allowed");
        }

        Request request = new Request.Builder()
                .url(parsedUrl)
                .build();

        try (Response response = client.newCall(request).execute()) {
            if (!response.isSuccessful()) {
                throw new IOException("Unexpected code " + response);
            }

            ResponseBody body = response.body();
            if (body != null) {
                return body.string();
            } else {
                return "";
            }
        }
    }

    /**
     * Custom DNS resolver to prevent DNS rebinding attacks and block resolution of internal IPs.
     */
    private static class SafeDns implements Dns {
        @Override
        public List<InetAddress> lookup(String hostname) throws UnknownHostException {
